noncompliant:
#pragma pack(push, 1)
struct A { int x; };
// Noncompliant: missing corresponding pop

compliant:
#pragma pack(push, 1) // Compliant: valid packing value
struct MyStruct { int a; char b; };
#pragma pack(pop) // Compliant: corresponding pop

#pragma pack(2) // Compliant: 2 is a valid packing value
struct A { int x; };
#pragma pack() // Compliant: reset to default
